CodeInjections.CodeInjection:
uniform float4 animOffset;
uniform float4 indicesAndBlend;
uniform float4 speeds;

    float pIndex = convertDefaultTexCoords( In, In.texCoords1.xy ).x;
    float mAnimOffset = 0.1*animOffset.x;
    
    float3 position0 = tex2Dlod(animArray, float3(pIndex,(cTime_s+mAnimOffset)*speeds.x, indicesAndBlend.x), 0).xyz;
    float3 position1 = tex2Dlod(animArray, float3(pIndex,(cTime_s+mAnimOffset)*speeds.y, indicesAndBlend.y), 0).xyz;
    // -- blending animations
    float3 mResult = In.position.xyz + lerp(position0, position1, indicesAndBlend.z);
    return mResult;
